import{z as e,b as d,c as o,i as r}from"./index-dc5fff9e.js";const i={class:"markdown-body"},s=r('<p>Bluetooth 4.0 传输距离提升到100米</p><h4>BLE的整体连接的步骤</h4><ol><li>开始扫描</li><li>开始连接设备</li><li>等待获取连接状态</li><li>获取或更改MTU包大小</li><li>获取Services信息</li><li>获取Characteristic信息</li></ol><p>disconnect()的作用 是用来断开连接的，但是用它断开连接后，连接所占用的资源并没有被释放，而只是暂时的断开连接，可以调用connect()方法进行重连 close()的作用 用来释放连接所占用的资源即释放BluetootheGatt的所有资源，一旦调用了该方法就不能再使用connect()方法进行重连了</p><h4>HID Report</h4><p>HID的服务UUID是0x1812， Rerport Protocl的Characteristic的UUID是0x2A4E，其特性是0x00表示Boot Protocol，0x01表示Report Protocol Report Characteristic的UUID是0x2A4D，用来传输Input Report，OutReport，Feature Report的。具有Notify功能。 Report Reference Characteristic的UUID是0x2908，两个字节，用于设置Report类型。</p><p>蓝牙HID report分为三种</p><ol><li>Input report：从hid device发送给hid host的封包</li><li>Output report：从hid host发送给hid device的封包 可以看出以上两种封包的input/output的方向都是就hid host而言的，而且要求低时延</li><li>Feature report：特性封包，是双向的</li></ol><p>HID有两条逻辑链路：</p><ol><li>HID Control：这个通道主要用于传输控制封包，在这个通道传输的封包称为同步封包（synchronous reports）,L2CAP的psm为0x0011</li><li>HID Interrupt：在这个通道传输的封包不需要确认，所以称为异步封包（asynchronous reports）,L2CAP的psm为0x0013</li></ol><p>HID封包命令 HID的封包格式header field只有一个byte,4bit的message type,4bit的parameter格式如下： HIDP MEssage Type(7-4) Parameter(3-0)</p><p>message type如下</p><table><thead><tr><th>Hex</th><th>Message Type</th><th>Sent By</th><th>Length(Octets)</th></tr></thead><tbody><tr><td>0</td><td>HANDSHAKE</td><td>Device</td><td>1</td></tr><tr><td>1</td><td>HID_CONTROL</td><td>Device and Host</td><td>1</td></tr><tr><td>2-3</td><td>Reserved</td><td>N/A</td><td></td></tr><tr><td>4</td><td>GET_REPORT</td><td>Host</td><td>1-4</td></tr><tr><td>5</td><td>SET_PEPORT</td><td>Host</td><td>1+Report Data Payload</td></tr><tr><td>6</td><td>GET_PROTOCOL</td><td>Host</td><td>1</td></tr><tr><td>7</td><td>SET_PROtOCOL</td><td>Host</td><td>1</td></tr><tr><td>A</td><td>DATA</td><td>Device and Host</td><td>1+Report Data Palyoad</td></tr></tbody></table><ol><li>HANDSHAKE封包 这个消息是只能从hid device的control channel发出，用于回复以下封包 1）SET_REPORT, SET_IDLE and SET_PROTOCOL requests 2）GET_REPORT, GET_PROTOCOL and GET_IDLE requests if an error is detected in the parameters of the initial request 3）a request with an unsupported message type</li><li>HID_CONTROL封包</li></ol><ol><li>SUSPEND/EXIT SUSPEND 这个是hid host发送给hid device进入省电模式/退出省电模式的命令，比如hid host发送给hid mouse发送SUSPEND的时候，mouse关闭LED等进入省电模式或者hid host发送给hid keyboard SUSPEND的时候，keyboard降低扫描按键的频率 2）VITUAL_CABLE_UNPLUG 这个命令是双向命令，hid host可以发送给hid device，同样hid device也可以发送给hid host，收到后断开连线 3 .GET_REPORT封包 这个封包是hid host发送给hid device的消息。hid device接受到这个封包后，需要在control通道上回复包含requeset信息的DATA type封包</li></ol><ol start="4"><li>SET_REPORT封包 这个封包是hid host发送给hid device的消息。</li><li>GET_PROTOCOL封包 用来获取Bluetooth HID device的Protocol Mode，然后Bluetooth HID device response一个DATA payload说明当前的Protocol Mode。</li><li>SET_PROTOCOL封包</li><li>DATA封包</li></ol>',16),l=[s],n={},D="",T=e({__name:"blog",setup(a,{expose:t}){return t({frontmatter:{},excerpt:void 0}),(h,c)=>(d(),o("div",i,l))}});export{T as default,D as excerpt,n as frontmatter};
